      ?obs sio:has-attribute ?mv . 
      ?mv sio:has-value ?sioValue .
      OPTIONAL { ?mv sio:has-unit ?u . ?u rdfs:label ?unit . }
    }
    BIND(COALESCE(?simpleResult, ?sioValue) AS ?value)
  }
}
ORDER BY DESC(?time)
"""
